const stdout = $input.first().json.stdout || '';
const date  = new Date().toISOString().split('T')[0];

// Extract the Discord: lines emitted by parser.py
const discordLines = stdout
  .split('\n')
  .filter(l => l.startsWith('Discord: '))
  .map(l => l.replace('Discord: ', ''));

// Pick embed colour from the worst severity found across all targets
const pickColor = (lines) => {
  if (lines.some(l => l.includes('Critical:'))) return 15158332; // red
  if (lines.some(l => l.includes('High:')))     return 15105570; // orange
  if (lines.some(l => l.includes('Medium:')))   return 16312092; // yellow
  return 5763719;                                                 // green
};

const description = discordLines.length
  ? discordLines.join('\n')
  : 'No findings reported.';

return [{
  json: {
    embeds: [{
      title: `VulnForge Scan Report — ${date}`,
      description,
      color: pickColor(discordLines),
      footer: { text: 'OWASP ZAP + Nuclei · VulnForge' },
      timestamp: new Date().toISOString()
    }]
  }
}];
